// engagementRow is the per-contact row emitted by `contacts engagement`.
// Aggregated locally over the synced reports table; computed fresh on every
// invocation because the API has no engagement-history endpoint.
type engagementRow struct {
	ID            string  `json:"id"`
	Email         string  `json:"email"`
	ListID        string  `json:"list_id,omitempty"`
	Opens         int     `json:"opens"`
	Clicks        int     `json:"clicks"`
	LastEngagedAt *string `json:"last_engaged_at"`
	InactiveDays  *int    `json:"inactive_days"`
}

// durationRE matches a simple Nd/Nh/Nm/Nw shape used by --inactive-since.
// Mirrors the lists-diff parser so users see one consistent grammar.
var durationRE = regexp.MustCompile(`^(\d+)([dhmw])$`)

// parseRelativeDuration converts "90d", "7d", "12h", "yesterday" to a
// time.Duration. Returns an error with the supported grammar baked in so a
// user-typed bad value surfaces a hint instead of a stack trace.
func parseRelativeDuration(input string) (time.Duration, error) {
	input = strings.TrimSpace(strings.ToLower(input))
	if input == "yesterday" {
		return 24 * time.Hour, nil
	}
	m := durationRE.FindStringSubmatch(input)
	if m == nil {
		return 0, fmt.Errorf("unknown duration format %q (try 1h, 2d, 1w, yesterday)", input)
	}
	n, err := strconv.Atoi(m[1])
	if err != nil || n < 0 {
		return 0, fmt.Errorf("invalid duration value %q", input)
	}
	switch m[2] {
	case "h":
		return time.Duration(n) * time.Hour, nil
	case "d":
		return time.Duration(n) * 24 * time.Hour, nil
	case "w":
		return time.Duration(n) * 7 * 24 * time.Hour, nil
	case "m":
		// "Nm" means minutes here, not months. Documented in --inactive-since
		// help. Months are ambiguous; users wanting ~30d should say `30d`.
		return time.Duration(n) * time.Minute, nil
	}
	return 0, fmt.Errorf("unknown duration unit in %q", input)
}

